// Job scheduler (callback style).
function schedule(job, done) {
  job(function (err) {
    done(err);
  });
}

module.exports = { schedule };

// Job scheduler (promise style, per ADR 0003).
async function schedule(job) {
  await job();
}

module.exports = { schedule };

